mapper.select:
SELECT A.*, B.TOTAL_CNT AS totalCnt FROM ( SELECT TT1.* FROM ( SELECT ROWNUM AS RNUM, T1.* FROM ( SELECT COURSE_NO AS courseNo , COURSE_NM AS courseNm , COURSE_INFO AS courseInfo , COURSE_PATH_NM AS coursePathNm , COURSE_DSTNC AS courseDstnc , COURSE_REQ_TM AS courseReqTm , COURSE_INQ_CNT AS courseInqCnt FROM COURSE WHERE 1=1
AND COURSE_NM LIKE '%' || #{searchWord} || '%'
ORDER BY COURSE_INQ_CNT DESC, COURSE_NO DESC ORDER BY COURSE_NO DESC
) T1 WHERE ROWNUM <= #{pageSize} * (#{pageNo} - 1) + #{pageSize} ) TT1 WHERE RNUM >= #{pageSize} * (#{pageNo} - 1) + 1 ) A CROSS JOIN ( SELECT COUNT(*) AS TOTAL_CNT FROM COURSE WHERE 1=1
AND COURSE_NM LIKE '%' || #{searchWord} || '%'
) B

mapper.update:
UPDATE COURSE
SET COURSE_NM      = #{courseNm}
  , COURSE_INFO    = #{courseInfo}
  , COURSE_PATH_NM = #{coursePathNm}
  , COURSE_DSTNC   = #{courseDstnc}
  , COURSE_REQ_TM  = #{courseReqTm}
WHERE COURSE_NO      = #{courseNo}

UPDATE COURSE
SET COURSE_INQ_CNT = NVL(COURSE_INQ_CNT, 0) + 1
WHERE COURSE_NO = #{courseNo}
